// MARK: - Crypto Utilities

struct CryptoUtils {
    static func sha256(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func ripemd160(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_MD5_DIGEST_LENGTH) * 2)
        data.withUnsafeBytes {
            _ = CC_MD5($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash.prefix(20))
    }
    
    static func hash160(_ data: Data) -> Data {
        return ripemd160(sha256(data))
    }
    
    static func doubleSha256(_ data: Data) -> Data {
        return sha256(sha256(data))
    }
}

// MARK: - Base58 Encoding

struct Base58 {
    private static let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
    
    static func encode(_ bytes: Data) -> String {
        var bytes = Array(bytes)
        var zerosCount = 0
        
        for b in bytes {
            if b != 0 { break }
            zerosCount += 1
        }
        
        bytes.removeFirst(zerosCount)
        
        var result = [Character]()
        var carry: Int
        var remainder: Int
        
        for byte in bytes {
            carry = Int(byte)
            
            for i in 0..<result.count {
                carry += Int(result[i].asciiValue! - 48) * 256
                result[i] = Character(String(carry % 58))
            }
            
            while carry > 0 {
                remainder = carry % 58
                carry /= 58
                result.append(Character(String(remainder)))
            }
        }
        
        for _ in 0..<zerosCount {
            result.append("1")
        }
        
        let encoded = result.reversed().map { alphabet[alphabet.index(alphabet.startIndex, offsetBy: Int(String($0))!)] }
        return String(encoded)
    }
    
    static func encodeCheck(_ data: Data) -> String {
        let checksum = CryptoUtils.doubleSha256(data).prefix(4)
        return encode(data + checksum)
    }
}

// MARK: - Secp256k1

class Secp256k1 {
    static let shared = Secp256k1()
    
    private let p = BigInt("FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEFFFFFC2F", radix: 16)!
    private let n = BigInt("FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141", radix: 16)!
    private let Gx = BigInt("79BE667EF9DCBBAC55A06295CE870B07029BFCDB2DCE28D959F2815B16F81798", radix: 16)!
    private let Gy = BigInt("483ADA7726A3C4655DA4FBFC0E1108A8FD17B448A68554199C47D08FFB10D4B8", radix: 16)!
    
    func generateKeyPair() -> (privateKey: Data, publicKey: Data) {
        let privateKey = generatePrivateKey()
        let publicKey = derivePublicKey(from: privateKey)
        return (privateKey, publicKey)
    }
    
    func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, 32, &bytes)
        return Data(bytes)
    }
    
    func derivePublicKey(from privateKey: Data) -> Data {
        let privKey = BigInt(privateKey)
        let point = multiplyPoint(Gx, Gy, privKey)
        
        var publicKey = Data([0x04])
        publicKey.append(point.x.toData(minBytes: 32))
        publicKey.append(point.y.toData(minBytes: 32))
        
        return compressPublicKey(publicKey)
    }
    
    func compressPublicKey(_ publicKey: Data) -> Data {
        guard publicKey.count == 65 && publicKey[0] == 0x04 else { return publicKey }
        
        let x = publicKey[1...32]
        let y = publicKey[33...64]
        let yBigInt = BigInt(Data(y))
        
        let prefix: UInt8 = yBigInt.isEven ? 0x02 : 0x03
        return Data([prefix]) + x
    }
    
    func sign(message: Data, privateKey: Data) -> Data {
        let z = BigInt(message.prefix(32))
        let privKey = BigInt(privateKey)
        
        var k: BigInt
        var r: BigInt
        var s: BigInt
        
        repeat {
            k = BigInt(generatePrivateKey())
            let point = multiplyPoint(Gx, Gy, k)
            r = point.x % n
            
            if r.isZero { continue }
            
            let kInv = k.modInverse(n)
            s = (kInv * (z + r * privKey)) % n
            
            if s > n / 2 {
                s = n - s
            }
            
        } while r.isZero || s.isZero
        
        return encodeDER(r: r, s: s)
    }
    
    private func encodeDER(r: BigInt, s: BigInt) -> Data {
        var result = Data()
        
        let rData = r.toData()
        let sData = s.toData()
        
        result.append(0x30)
        result.append(UInt8(4 + rData.count + sData.count))
        
        result.append(0x02)
        result.append(UInt8(rData.count))
        result.append(rData)
        
        result.append(0x02)
        result.append(UInt8(sData.count))
        result.append(sData)
        
        return result
    }
    
    private func multiplyPoint(_ x: BigInt, _ y: BigInt, _ scalar: BigInt) -> (x: BigInt, y: BigInt) {
        var result: (x: BigInt, y: BigInt)? = nil
        var temp = (x: x, y: y)
        var k = scalar
        
        while k > 0 {
            if k & 1 == 1 {
                if result == nil {
                    result = temp
                } else {
                    result = addPoints(result!, temp)
                }
            }
            temp = doublePoint(temp)
            k >>= 1
        }
        
        return result ?? (x: BigInt(0), y: BigInt(0))
    }
    
    private func addPoints(_ p1: (x: BigInt, y: BigInt), _ p2: (x: BigInt, y: BigInt)) -> (x: BigInt, y: BigInt) {
        let slope = ((p2.y - p1.y) * (p2.x - p1.x).modInverse(p)) % p
        let x = (slope * slope - p1.x - p2.x) % p
        let y = (slope * (p1.x - x) - p1.y) % p
        return (x: (x + p) % p, y: (y + p) % p)
    }
    
    private func doublePoint(_ point: (x: BigInt, y: BigInt)) -> (x: BigInt, y: BigInt) {
        let slope = ((BigInt(3) * point.x * point.x) * (BigInt(2) * point.y).modInverse(p)) % p
        let x = (slope * slope - BigInt(2) * point.x) % p
        let y = (slope * (point.x - x) - point.y) % p
        return (x: (x + p) % p, y: (y + p) % p)
    }
}

// MARK: - BigInt Implementation

struct BigInt: Comparable, Equatable {
    private var magnitude: [UInt32]
    private var isNegative: Bool
    
    init(_ value: Int) {
        if value < 0 {
            self.magnitude = [UInt32(-value)]
            self.isNegative = true
        } else {
            self.magnitude = [UInt32(value)]
            self.isNegative = false
        }
        normalize()
    }
    
    init(_ data: Data) {
        var mag: [UInt32] = []
        var temp = data
        
        while temp.count > 0 {
            let count = min(temp.count, 4)
            let chunk = temp.suffix(count)
            temp = temp.dropLast(count)
            
            var value: UInt32 = 0
            for byte in chunk {
                value = (value << 8) | UInt32(byte)
            }
            mag.append(value)
        }
        
        self.magnitude = mag.reversed()
        self.isNegative = false
        normalize()
    }
    
    init?(_ string: String, radix: Int = 10) {
        self.magnitude = [0]
        self.isNegative = false
        
        for char in string {
            guard let digit = char.hexDigitValue else { return nil }
            guard digit < radix else { return nil }
            
            self = self * BigInt(radix) + BigInt(digit)
        }
        normalize()
    }
    
    private mutating func normalize() {
        while magnitude.count > 1 && magnitude.last == 0 {
            magnitude.removeLast()
        }
        if magnitude.isEmpty || (magnitude.count == 1 && magnitude[0] == 0) {
            magnitude = [0]
            isNegative = false
        }
    }
    
    var isZero: Bool {
        return magnitude.count == 1 && magnitude[0] == 0
    }
    
    var isEven: Bool {
        return magnitude[0] & 1 == 0
    }
    
    func toData(minBytes: Int = 0) -> Data {
        var data = Data()
        
        for word in magnitude.reversed() {
            var value = word
            var bytes: [UInt8] = []
            
            for _ in 0..<4 {
                bytes.insert(UInt8(value & 0xFF), at: 0)
                value >>= 8
            }
            
            data.append(contentsOf: bytes)
        }
        
        while data.first == 0 && data.count > minBytes {
            data.removeFirst()
        }
        
        while data.count < minBytes {
            data.insert(0, at: 0)
        }
        
        return data
    }
    
    static func + (lhs: BigInt, rhs: BigInt) -> BigInt {
        if lhs.isNegative == rhs.isNegative {
            var result = BigInt(0)
            result.magnitude = addMagnitudes(lhs.magnitude, rhs.magnitude)
            result.isNegative = lhs.isNegative
            result.normalize()
            return result
        } else {
            return lhs - BigInt.negate(rhs)
        }
    }
    
    static func - (lhs: BigInt, rhs: BigInt) -> BigInt {
        if lhs.isNegative != rhs.isNegative {
            var result = BigInt(0)
            result.magnitude = addMagnitudes(lhs.magnitude, rhs.magnitude)
            result.isNegative = lhs.isNegative
            result.normalize()
            return result
        }
        
        let cmp = compareMagnitudes(lhs.magnitude, rhs.magnitude)
        var result = BigInt(0)
        
        if cmp >= 0 {
            result.magnitude = subtractMagnitudes(lhs.magnitude, rhs.magnitude)
            result.isNegative = lhs.isNegative
        } else {
            result.magnitude = subtractMagnitudes(rhs.magnitude, lhs.magnitude)
            result.isNegative = !lhs.isNegative
        }
        
        result.normalize()
        return result
    }
    
    static func * (lhs: BigInt, rhs: BigInt) -> BigInt {
        var result = BigInt(0)
        result.magnitude = multiplyMagnitudes(lhs.magnitude, rhs.magnitude)
        result.isNegative = lhs.isNegative != rhs.isNegative
        result.normalize()
        return result
    }
    
    static func / (lhs: BigInt, rhs: BigInt) -> BigInt {
        let (quotient, _) = divideWithRemainder(lhs, rhs)
        return quotient
    }
    
    static func % (lhs: BigInt, rhs: BigInt) -> BigInt {
        let (_, remainder) = divideWithRemainder(lhs, rhs)
        return remainder
    }
    
    static func & (lhs: BigInt, rhs: BigInt) -> BigInt {
        return BigInt(Int(lhs.magnitude[0]) & Int(rhs.magnitude[0]))
    }
    
    static func >> (lhs: BigInt, rhs: Int) -> BigInt {
        var result = lhs
        result.magnitude[0] >>= rhs
        result.normalize()
        return result
    }
    
    static func < (lhs: BigInt, rhs: BigInt) -> Bool {
        if lhs.isNegative != rhs.isNegative {
            return lhs.isNegative
        }
        let cmp = compareMagnitudes(lhs.magnitude, rhs.magnitude)
        return lhs.isNegative ? cmp > 0 : cmp < 0
    }
    
    static func == (lhs: BigInt, rhs: BigInt) -> Bool {
        return lhs.isNegative == rhs.isNegative && lhs.magnitude == rhs.magnitude
    }
    
    private static func addMagnitudes(_ a: [UInt32], _ b: [UInt32]) -> [UInt32] {
        var result: [UInt32] = []
        var carry: UInt64 = 0
        let maxLen = max(a.count, b.count)
        
        for i in 0..<maxLen {
            let aVal = i < a.count ? UInt64(a[i]) : 0
            let bVal = i < b.count ? UInt64(b[i]) : 0
            let sum = aVal + bVal + carry
            result.append(UInt32(sum & 0xFFFFFFFF))
            carry = sum >> 32
        }
        
        if carry > 0 {
            result.append(UInt32(carry))
        }
        
        return result
    }
    
    private static func subtractMagnitudes(_ a: [UInt32], _ b: [UInt32]) -> [UInt32] {
        var result: [UInt32] = []
        var borrow: Int64 = 0
        
        for i in 0..<a.count {
            let aVal = Int64(a[i])
            let bVal = i < b.count ? Int64(b[i]) : 0
            var diff = aVal - bVal - borrow
            
            if diff < 0 {
                diff += 0x100000000
                borrow = 1
            } else {
                borrow = 0
            }
            
            result.append(UInt32(diff))
        }
        
        return result
    }
    
    private static func multiplyMagnitudes(_ a: [UInt32], _ b: [UInt32]) -> [UInt32] {
        var result = [UInt32](repeating: 0, count: a.count + b.count)
        
        for i in 0..<a.count {
            var carry: UInt64 = 0
            for j in 0..<b.count {
                let product = UInt64(a[i]) * UInt64(b[j]) + UInt64(result[i + j]) + carry
                result[i + j] = UInt32(product & 0xFFFFFFFF)
                carry = product >> 32
            }
            result[i + b.count] = UInt32(carry)
        }
        
        return result
    }
    
    private static func compareMagnitudes(_ a: [UInt32], _ b: [UInt32]) -> Int {
        if a.count != b.count {
            return a.count < b.count ? -1 : 1
        }
        
        for i in (0..<a.count).reversed() {
            if a[i] != b[i] {
                return a[i] < b[i] ? -1 : 1
            }
        }
        
        return 0
    }
    
    private static func divideWithRemainder(_ dividend: BigInt, _ divisor: BigInt) -> (quotient: BigInt, remainder: BigInt) {
        if divisor.isZero {
            fatalError("Division by zero")
        }
        
        var quotient = BigInt(0)
        var remainder = dividend
        
        while remainder >= divisor {
            remainder = remainder - divisor
            quotient = quotient + BigInt(1)
        }
        
        return (quotient, remainder)
    }
    
    private static func negate(_ value: BigInt) -> BigInt {
        var result = value
        result.isNegative = !value.isNegative
        return result
    }
    
    func modInverse(_ modulus: BigInt) -> BigInt {
        var t = BigInt(0)
        var newT = BigInt(1)
        var r = modulus
        var newR = self
        
        while !newR.isZero {
            let quotient = r / newR
            
            let tempT = t
            t = newT
            newT = tempT - quotient * newT
            
            let tempR = r
            r = newR
            newR = tempR - quotient * newR
        }
        
        if t < BigInt(0) {
            t = t + modulus
        }
        
        return t % modulus
    }
}

// MARK: - Wallet

class Wallet {
    private(set) var privateKey: Data
    private(set) var publicKey: Data
    private(set) var address: String
    
    init() {
        let keyPair = Secp256k1.shared.generateKeyPair()
        self.privateKey = keyPair.privateKey
        self.publicKey = keyPair.publicKey
        self.address = Wallet.deriveAddress(from: keyPair.publicKey)
    }
    
    init(privateKey: Data) {
        self.privateKey = privateKey
        self.publicKey = Secp256k1.shared.derivePublicKey(from: privateKey)
        self.address = Wallet.deriveAddress(from: self.publicKey)
    }
    
    static func deriveAddress(from publicKey: Data) -> String {
        let hash = CryptoUtils.hash160(publicKey)
        var payload = Data([0x00])
        payload.append(hash)
        return Base58.encodeCheck(payload)
    }
    
    func getPrivateKeyWIF() -> String {
        var payload = Data([0x80])
        payload.append(privateKey)
        payload.append(0x01)
        return Base58.encodeCheck(payload)
    }
}

// MARK: - Transaction

struct Transaction {
    struct Input {
        let previousTxHash: Data
        let outputIndex: UInt32
        let scriptSig: Data
        let sequence: UInt32
        
        func serialize() -> Data {
            var data = Data()
            data.append(previousTxHash.reversed())
            data.append(withUnsafeBytes(of: outputIndex.littleEndian) { Data($0) })
            data.append(UInt8(scriptSig.count))
            data.append(scriptSig)
            data.append(withUnsafeBytes(of: sequence.littleEndian) { Data($0) })
            return data
        }
    }
    
    struct Output {
        let value: UInt64
        let scriptPubKey: Data
        
        func serialize() -> Data {
            var data = Data()
            data.append(withUnsafeBytes(of: value.littleEndian) { Data($0) })
            data.append(UInt8(scriptPubKey.count))
            data.append(scriptPubKey)
            return data
        }
    }
    
    let version: UInt32
    var inputs: [Input]
    let outputs: [Output]
    let lockTime: UInt32
    
    init(version: UInt32 = 1, inputs: [Input], outputs: [Output], lockTime: UInt32 = 0) {
        self.version = version
        self.inputs = inputs
        self.outputs = outputs
        self.lockTime = lockTime
    }
    
    func serialize() -> Data {
        var data = Data()
        data.append(withUnsafeBytes(of: version.littleEndian) { Data($0) })
        data.append(UInt8(inputs.count))
        
        for input in inputs {
            data.append(input.serialize())
        }
        
        data.append(UInt8(outputs.count))
        
        for output in outputs {
            data.append(output.serialize())
        }
        
        data.append(withUnsafeBytes(of: lockTime.littleEndian) { Data($0) })
        return data
    }
    
    func getHash() -> Data {
        return CryptoUtils.doubleSha256(serialize())
    }
    
    func getId() -> String {
        return getHash().reversed().map { String(format: "%02x", $0) }.joined()
    }
    
    mutating func sign(at index: Int, privateKey: Data, scriptPubKey: Data) {
        var tempInputs = inputs
        
        for i in 0..<tempInputs.count {
            tempInputs[i] = Input(
                previousTxHash: tempInputs[i].previousTxHash,
                outputIndex: tempInputs[i].outputIndex,
                scriptSig: i == index ? scriptPubKey : Data(),
                sequence: tempInputs[i].sequence
            )
        }
        
        let tempTx = Transaction(version: version, inputs: tempInputs, outputs: outputs, lockTime: lockTime)
        var sigHash = tempTx.serialize()
        sigHash.append(withUnsafeBytes(of: UInt32(1).littleEndian) { Data($0) })
        
        let hash = CryptoUtils.doubleSha256(sigHash)
        let signature = Secp256k1.shared.sign(message: hash, privateKey: privateKey)
        
        var scriptSig = Data()
        scriptSig.append(UInt8(signature.count + 1))
        scriptSig.append(signature)
        scriptSig.append(0x01)
        
        let publicKey = Secp256k1.shared.derivePublicKey(from: privateKey)
        scriptSig.append(UInt8(publicKey.count))
        scriptSig.append(publicKey)
        
        inputs[index] = Input(
            previousTxHash: inputs[index].previousTxHash,
            outputIndex: inputs[index].outputIndex,
            scriptSig: scriptSig,
            sequence: inputs[index].sequence
        )
    }
    
    static func createP2PKHScript(address: String) -> Data {
        var script = Data()
        script.append(0x76)
        script.append(0xa9)
        script.append(0x14)
        
        let decoded = Data(repeating: 0, count: 25)
        script.append(decoded[1...20])
        
        script.append(0x88)
        script.append(0xac)
        
        return script
    }
}

// MARK: - Keychain Storage

class KeychainManager {
    static let shared = KeychainManager()
    private let serviceName = "com.cryptowallet.keys"
    
    func save(privateKey: Data, for account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecValueData as String: privateKey,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func load(for account: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        return status == errSecSuccess ? result as? Data : nil
    }
    
    func delete(for account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

// MARK: - Blockchain API

class BlockchainAPI {
    static let shared = BlockchainAPI()
    private let baseURL = "https://blockchain.info"
    
    func getBalance(for address: String, completion: @escaping (Result<UInt64, Error>) -> Void) {
        let urlString = "\(baseURL)/q/addressbalance/\(address)"
        guard let url = URL(string: urlString) else { return }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let balanceString = String(data: data, encoding: .utf8),
                  let balance = UInt64(balanceString) else {
                completion(.failure(NSError(domain: "Invalid response", code: -1)))
                return
            }
            
            completion(.success(balance))
        }.resume()
    }
    
    func getUnspentOutputs(for address: String, completion: @escaping (Result<[[String: Any]], Error>) -> Void) {
        let urlString = "\(baseURL)/unspent?active=\(address)"
        guard let url = URL(string: urlString) else { return }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let outputs = json["unspent_outputs"] as? [[String: Any]] else {
                completion(.failure(NSError(domain: "Invalid response", code: -1)))
                return
            }
            
            completion(.success(outputs))
        }.resume()
    }
    
    func broadcastTransaction(_ txHex: String, completion: @escaping (Result<String, Error>) -> Void) {
        let urlString = "\(baseURL)/pushtx"
        guard let url = URL(string: urlString) else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/x-www-form-urlencoded", forHTTPHeaderField: "Content-Type")
        request.httpBody = "tx=\(txHex)".data(using: .utf8)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let result = String(data: data, encoding: .utf8) else {
                completion(.failure(NSError(domain: "Invalid response", code: -1)))
                return
            }
            
            completion(.success(result))
        }.resume()
    }
}

