        addressLabel.textAlignment = .center
        addressLabel.text = "Address:\n\(wallet.address)"
        
        balanceLabel.font = .systemFont(ofSize: 32, weight: .bold)
        balanceLabel.textAlignment = .center
        balanceLabel.text = "0.00000000 BTC"
        
        privateKeyButton.setTitle("Show Private Key", for: .normal)
        privateKeyButton.addTarget(self, action: #selector(showPrivateKey), for: .touchUpInside)
        
        sendButton.setTitle("Send", for: .normal)
        sendButton.backgroundColor = .systemBlue
        sendButton.setTitleColor(.white, for: .normal)
        sendButton.layer.cornerRadius = 8
        sendButton.addTarget(self, action: #selector(sendTapped), for: .touchUpInside)
        
        receiveButton.setTitle("Receive", for: .normal)
        receiveButton.backgroundColor = .systemGreen
        receiveButton.setTitleColor(.white, for: .normal)
        receiveButton.layer.cornerRadius = 8
        receiveButton.addTarget(self, action: #selector(receiveTapped), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [addressLabel, balanceLabel, privateKeyButton, sendButton, receiveButton])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            sendButton.heightAnchor.constraint(equalToConstant: 50),
            receiveButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    private func loadBalance() {
        BlockchainAPI.shared.getBalance(for: wallet.address) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    let btc = Double(balance) / 100000000.0
                    self?.balanceLabel.text = String(format: "%.8f BTC", btc)
                case .failure:
                    self?.balanceLabel.text = "Error loading balance"
                }
            }
        }
    }
    
    @objc private func showPrivateKey() {
        let alert = UIAlertController(title: "Private Key", message: wallet.getPrivateKeyWIF(), preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Copy", style: .default) { _ in
            UIPasteboard.general.string = self.wallet.getPrivateKeyWIF()
        })
        alert.addAction(UIAlertAction(title: "Close", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func sendTapped() {
        let vc = SendViewController(wallet: wallet)
        navigationController?.pushViewController(vc, animated: true)
    }
    
    @objc private func receiveTapped() {
        let vc = ReceiveViewController(address: wallet.address)
        navigationController?.pushViewController(vc, animated: true)
    }
}

class SendViewController: UIViewController {
    private let wallet: Wallet
    private let toAddressField = UITextField()
    private let amountField = UITextField()
    private let sendButton = UIButton(type: .system)
    
    init(wallet: Wallet) {
        self.wallet = wallet
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        view.backgroundColor = .systemBackground
        title = "Send Bitcoin"
        
        setupUI()
    }
    
    private func setupUI() {
        toAddressField.placeholder = "Recipient Address"
        toAddressField.borderStyle = .roundedRect
        toAddressField.autocapitalizationType = .none
        
        amountField.placeholder = "Amount (BTC)"
        amountField.borderStyle = .roundedRect
        amountField.keyboardType = .decimalPad
        
        sendButton.setTitle("Send Transaction", for: .normal)
        sendButton.backgroundColor = .systemBlue
        sendButton.setTitleColor(.white, for: .normal)
        sendButton.layer.cornerRadius = 8
        sendButton.addTarget(self, action: #selector(sendTransaction), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [toAddressField, amountField, sendButton])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 40),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            toAddressField.heightAnchor.constraint(equalToConstant: 44),
            amountField.heightAnchor.constraint(equalToConstant: 44),
            sendButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    @objc private func sendTransaction() {
        guard let toAddress = toAddressField.text, !toAddress.isEmpty,
              let amountString = amountField.text,
              let amount = Double(amountString) else {
            showAlert(message: "Please fill in all fields")
            return
        }
        
        let satoshis = UInt64(amount * 100000000)
        
        BlockchainAPI.shared.getUnspentOutputs(for: wallet.address) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let outputs):
                self.createAndBroadcastTransaction(outputs: outputs, toAddress: toAddress, amount: satoshis)
            case .failure(let error):
                DispatchQueue.main.async {
                    self.showAlert(message: "Error fetching outputs: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func createAndBroadcastTransaction(outputs: [[String: Any]], toAddress: String, amount: UInt64) {
        guard let firstOutput = outputs.first,
              let txHash = firstOutput["tx_hash_big_endian"] as? String,
              let outputIndex = firstOutput["tx_output_n"] as? UInt32,
              let value = firstOutput["value"] as? UInt64 else {
            showAlert(message: "Invalid output data")
            return
        }
        
        let txHashData = Data(txHash.chunks(ofCount: 2).compactMap { UInt8($0, radix: 16) })
        
        let input = Transaction.Input(
            previousTxHash: txHashData,
            outputIndex: outputIndex,
            scriptSig: Data(),
            sequence: 0xffffffff
        )
        
        let toOutput = Transaction.Output(
            value: amount,
            scriptPubKey: Transaction.createP2PKHScript(address: toAddress)
        )
        
        let fee: UInt64 = 10000
        let change = value - amount - fee
        
        var outputs: [Transaction.Output] = [toOutput]
        
        if change > 0 {
            let changeOutput = Transaction.Output(
                value: change,
                scriptPubKey: Transaction.createP2PKHScript(address: wallet.address)
            )
            outputs.append(changeOutput)
        }
        
        var transaction = Transaction(inputs: [input], outputs: outputs)
        
        let scriptPubKey = Transaction.createP2PKHScript(address: wallet.address)
        transaction.sign(at: 0, privateKey: wallet.privateKey, scriptPubKey: scriptPubKey)
        
        let txHex = transaction.serialize().map { String(format: "%02x", $0) }.joined()
        
        BlockchainAPI.shared.broadcastTransaction(txHex) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let txId):
                    self?.showAlert(message: "Transaction sent!\nID: \(txId)")
                case .failure(let error):
                    self?.showAlert(message: "Error broadcasting: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class ReceiveViewController: UIViewController {
    private let address: String
    private let addressLabel = UILabel()
    private let qrImageView = UIImageView()
    private let copyButton = UIButton(type: .system)
    
    init(address: String) {
        self.address = address
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        view.backgroundColor = .systemBackground
        title = "Receive Bitcoin"
        
        setupUI()
    }
    
    private func setupUI() {
        addressLabel.text = address
        addressLabel.font = .systemFont(ofSize: 14, weight: .medium)
        addressLabel.numberOfLines = 0
        addressLabel.textAlignment = .center
        
        qrImageView.contentMode = .scaleAspectFit
        qrImageView.image = generateQRCode(from: address)
        
        copyButton.setTitle("Copy Address", for: .normal)
        copyButton.backgroundColor = .systemBlue
        copyButton.setTitleColor(.white, for: .normal)
        copyButton.layer.cornerRadius = 8
        copyButton.addTarget(self, action: #selector(copyAddress), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [qrImageView, addressLabel, copyButton])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.alignment = .center
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            qrImageView.widthAnchor.constraint(equalToConstant: 250),
            qrImageView.heightAnchor.constraint(equalToConstant: 250),
            copyButton.heightAnchor.constraint(equalToConstant: 50),
            copyButton.widthAnchor.constraint(equalTo: stackView.widthAnchor)
        ])
    }
    
    private func generateQRCode(from string: String) -> UIImage? {
        let data = string.data(using: .utf8)
        
        if let filter = CIFilter(name: "CIQRCodeGenerator") {
            filter.setValue(data, forKey: "inputMessage")
            let transform = CGAffineTransform(scaleX: 10, y: 10)
            
            if let output = filter.outputImage?.transformed(by: transform) {
                return UIImage(ciImage: output)
            }
        }
        
        return nil
    }
    
    @objc private func copyAddress() {
        UIPasteboard.general.string = address
        
        let alert = UIAlertController(title: "Copied!", message: "Address copied to clipboard", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension String {
    func chunks(ofCount count: Int) -> [String] {
        var result: [String] = []
        var currentIndex = startIndex
        
        while currentIndex < endIndex {
            let endIndex = index(currentIndex, offsetBy: count, limitedBy: self.endIndex) ?? self.endIndex
            result.append(String(self[currentIndex..<endIndex]))
            currentIndex = endIndex
        }
        
        return result
    }
}

